4: List *list_create(void) {
5:     List *list = malloc(sizeof(List));
6:     list->head = NULL;
7:     list->length = 0;
8:     return list;
9: }
10: 
11: void list_push(List *list, int value) {
12:     Node *node = malloc(sizeof(Node));
13:     node->data = value;
14:     node->next = list->head;
15:     list->head = node;
16:     list->length++;
17: }
18: 
19: int list_pop(List *list) {
20:     if (!list->head) return -1;
21:     Node *old = list->head;
22:     int value = old->data;
23:     list->head = old->next;
24:     free(old);
25:     list->length--;
26:     return value;
27: }
28: 
29: void list_free(List *list) {
30:     while (list->head) list_pop(list);
31:     free(list);
32: }

