void list_reverse(List *list) {
    Node *prev = NULL;
    Node *curr = list->head;
    Node *next;
    while (curr != NULL) {
        next = curr->next;
        curr->next = prev;
        prev = curr;
        curr = next;
    }
    list->head = prev;
}

